CREATE TABLE public.tool_usage (id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE, tool_id TEXT NOT NULL, tool_name TEXT NOT NULL, category TEXT NOT NULL, created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT now()); ALTER TABLE public.tool_usage ENABLE ROW LEVEL SECURITY; CREATE POLICY "Users can view their own tool usage" ON public.tool_usage FOR SELECT USING (auth.uid() = user_id); CREATE POLICY "Users can insert their own tool usage" ON public.tool_usage FOR INSERT WITH CHECK (auth.uid() = user_id); CREATE INDEX idx_tool_usage_user_id ON public.tool_usage(user_id); CREATE INDEX idx_tool_usage_tool_id ON public.tool_usage(tool_id);